def validate_filename(filename: str) -> str:
    fn = (filename or "").strip()
    if not fn:
        raise HTTPException(status_code=400, detail="Uploaded file must have a filename.")
    _, ext = os.path.splitext(fn.lower())
    if ALLOWED_EXT and ext not in ALLOWED_EXT:
        raise HTTPException(status_code=400, detail=f"Unsupported model file extension: {ext}")
    return fn


def read_upload_limited(file: UploadFile, max_bytes: int) -> bytes:
    buf = io.BytesIO()
    total = 0
    chunk_size = 1024 * 1024
    while True:
        chunk = file.file.read(chunk_size)
        if not chunk:
            break
        total += len(chunk)
        if total > max_bytes:
            raise HTTPException(status_code=413, detail=f"Upload too large (>{max_bytes} bytes).")
        buf.write(chunk)
    return buf.getvalue()


